import { useState, useEffect } from "react";
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
} from "@mui/material";
import { Edit, DeleteIcon } from "@mui/icons-material";
import API from "../../api/axios";

export default function ProjectManagement() {
  const [search, setSearch] = useState("");
  const [data, setData] = useState([]);

  // 🔹 Add Modal
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState({
    username: "",
    password: "",
    project_name: "",
    description: "",
    start_date: "",
    end_date: "",
  });

  // 🔹 Edit Modal
  const [editOpen, setEditOpen] = useState(false);
  const [editData, setEditData] = useState(null);

  // 🔄 Fetch Data
  const fetchProjects = async () => {
    try {
      const res = await API.get("projects/");
      setData(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  // 🚀 CREATE
  const createProjectUser = async () => {
    try {
      await API.post("create-project-user/", form);
      alert("Created ✅");
      setOpen(false);
      fetchProjects();
    } catch (err) {
      console.log(err);
      alert("Error ❌");
    }
  };

  // ✏️ UPDATE
  const updateProject = async () => {
    try {
      await API.put(`projects/${editData.id}/`, editData);
      setEditOpen(false);
      fetchProjects();
    } catch (err) {
      console.log(err);
    }
  };

  // 🗑 DELETE
  const deleteProject = async (id) => {
    if (!window.confirm("Delete project?")) return;

    try {
      await API.delete(`projects/${id}/delete/`, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
      });

      fetchProjects(); // refresh table
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <Box sx={{ p: 4, display: "flex", justifyContent: "center" }}>
      <Paper
        elevation={12}
        sx={{
          width: "100%",
          maxWidth: 1200,
          p: 4,
          borderRadius: "20px",
          background: "linear-gradient(145deg, #f0f0f0, #ffffff)",
          boxShadow: "20px 20px 60px #d9d9d9, -20px -20px 60px #ffffff",
        }}
      >
        {/* 🔹 HEADER */}
        <Box sx={{ display: "flex", justifyContent: "space-between", mb: 3 }}>
          <Typography variant="h5" fontWeight="bold">
            Project Management
          </Typography>

          <Button
            variant="contained"
            onClick={() => setOpen(true)}
            sx={{
              borderRadius: "12px",
              background: "linear-gradient(135deg, #1976d2, #42a5f5)",
              boxShadow: "0px 4px 15px rgba(0,0,0,0.2)",
            }}
          >
            + Add User
          </Button>
        </Box>

        {/* 🔍 SEARCH */}
        <TextField
          fullWidth
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{
            mb: 3,
            "& .MuiOutlinedInput-root": {
              borderRadius: "12px",
              background: "#fff",
              boxShadow: "inset 2px 2px 6px #d1d1d1",
            },
          }}
        />

        {/* 📊 TABLE */}
        <Paper
          sx={{
            borderRadius: "15px",
            overflow: "auto",
            boxShadow: "inset 3px 3px 8px #d1d1d1, inset -3px -3px 8px #ffffff",
          }}
        >
          <Table>
            <TableHead>
              <TableRow
                sx={{
                  background: "linear-gradient(135deg, #1976d2, #42a5f5)",
                }}
              >
                {[
                  "Project Name",
                  "User Name",
                  "Description",
                  "Start Date",
                  "End Date",
                  "Joined Date",
                  "Actions",
                ].map((head) => (
                  <TableCell key={head} sx={{ color: "#fff" }}>
                    <b>{head}</b>
                  </TableCell>
                ))}
              </TableRow>
            </TableHead>

            <TableBody>
              {data
                .filter((d) =>
                  d.project_name?.toLowerCase().includes(search.toLowerCase()),
                )
                .map((row) => (
                  <TableRow
                    key={row.id}
                    sx={{
                      transition: "0.3s",
                      "&:hover": {
                        background: "#f5faff",
                        transform: "scale(1.01)",
                      },
                    }}
                  >
                    <TableCell>{row.project_name}</TableCell>
                    <TableCell>{row.user}</TableCell>
                    <TableCell>{row.description}</TableCell>
                    <TableCell>{row.start}</TableCell>
                    <TableCell>{row.end}</TableCell>
                    <TableCell>
                      {row.joined
                        ? new Date(row.joined).toLocaleDateString()
                        : "-"}
                    </TableCell>

                    <TableCell>
                      <IconButton
                        onClick={() => {
                          setEditData(row);
                          setEditOpen(true);
                        }}
                        sx={{ color: "#1976d2" }}
                      >
                        <Edit />
                      </IconButton>

                      <IconButton
                        onClick={() => deleteProject(row.id)}
                        sx={{ color: "#d32f2f" }}
                      >
                        <DeleteIcon
                          onClick={() => deleteProject(row.id)}
                          style={{ cursor: "pointer", color: "red" }}
                        />
                      </IconButton>
                    </TableCell>
                  </TableRow>
                ))}
            </TableBody>
          </Table>
        </Paper>

        {/* 🚀 ADD MODAL */}
        <Dialog open={open} onClose={() => setOpen(false)} fullWidth>
          <DialogTitle>Create Project User</DialogTitle>

          <DialogContent
            sx={{ display: "flex", flexDirection: "column", gap: 2 }}
          >
            <TextField
              label="Username"
              onChange={(e) => setForm({ ...form, username: e.target.value })}
            />
            <TextField
              label="Password"
              type="password"
              onChange={(e) => setForm({ ...form, password: e.target.value })}
            />
            <TextField
              label="Project Name"
              onChange={(e) =>
                setForm({ ...form, project_name: e.target.value })
              }
            />
            <TextField
              label="Description"
              onChange={(e) =>
                setForm({ ...form, description: e.target.value })
              }
            />
            <TextField
              type="date"
              onChange={(e) => setForm({ ...form, start_date: e.target.value })}
            />
            <TextField
              type="date"
              onChange={(e) => setForm({ ...form, end_date: e.target.value })}
            />
          </DialogContent>

          <DialogActions>
            <Button onClick={() => setOpen(false)}>Cancel</Button>
            <Button onClick={createProjectUser}>Create</Button>
          </DialogActions>
        </Dialog>

        {/* ✏️ EDIT MODAL */}
        <Dialog open={editOpen} onClose={() => setEditOpen(false)} fullWidth>
          <DialogTitle>Edit Project</DialogTitle>

          <DialogContent>
            <TextField
              fullWidth
              label="Project Name"
              value={editData?.project_name || ""}
              onChange={(e) =>
                setEditData({
                  ...editData,
                  project_name: e.target.value,
                })
              }
            />
          </DialogContent>

          <DialogActions>
            <Button onClick={() => setEditOpen(false)}>Cancel</Button>
            <Button onClick={updateProject}>Update</Button>
          </DialogActions>
        </Dialog>
      </Paper>
    </Box>
  );
}
